import { QueryClient } from '@tanstack/react-query';
import { PersistQueryClientProvider } from '@tanstack/react-query-persist-client';
import { createAsyncStoragePersister } from '@tanstack/query-async-storage-persister';
import AsyncStorage from '@react-native-async-storage/async-storage';

const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      gcTime: 1000 * 60 * 60 * 24, // 24 heures
      staleTime: 1000 * 60 * 5, // 5 minutes
    },
  },
});

const asyncStoragePersister = createAsyncStoragePersister({
  storage: AsyncStorage,
  key: 'react-query-cache',
  throttleTime: 1000,
});

export default function App() {
  return (
    &lt;PersistQueryClientProvider
      client={queryClient}
      persistOptions={{ persister: asyncStoragePersister }}
    &gt;
      {/* Le reste de l'application */}
    &lt;/PersistQueryClientProvider&gt;
  );
}

import { useQuery } from '@tanstack/react-query';
import { View, Text, FlatList, ActivityIndicator } from 'react-native';
import axios from 'axios';

const fetchProducts = async () => {
  const response = await axios.get('https://api.example.com/products');
  return response.data;
};

export default function ProduitsScreen() {
  const { data: products, isLoading, error, refetch } = useQuery({
    queryKey: ['products'],
    queryFn: fetchProducts,
    staleTime: 60000,
  });

  if (isLoading) {
    return &lt;ActivityIndicator size="large" /&gt;;
  }

  if (error) {
    return (
      &lt;View&gt;
        &lt;Text&gt;Erreur : {error.message}&lt;/Text&gt;
      &lt;/View&gt;
    );
  }

  return (
    &lt;FlatList
      data={products}
      keyExtractor={(item) => item.id.toString()}
      renderItem={({ item }) => &lt;Text&gt;{item.name}&lt;/Text&gt;}
      onRefresh={refetch}
      refreshing={isLoading}
    /&gt;
  );
}

import { useMutation, useQueryClient } from '@tanstack/react-query';
import { View, TextInput, Button, Alert } from 'react-native';
import axios from 'axios';

const addProduct = async (newProduct) => {
  const response = await axios.post('https://api.example.com/products', newProduct);
  return response.data;
};

export default function AjoutProduitForm() {
  const queryClient = useQueryClient();
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');

  const mutation = useMutation({
    mutationFn: addProduct,
    onSuccess: () => {
      // Invalider la requête 'products' pour forcer un re-fetch
      queryClient.invalidateQueries({ queryKey: ['products'] });
      Alert.alert('Succès', 'Produit ajouté avec succès');
      setName('');
      setPrice('');
    },
    onError: (error) => {
      Alert.alert('Erreur', error.message);
    },
  });

  const handleSubmit = () => {
    if (!name || !price) {
      Alert.alert('Erreur', 'Veuillez remplir tous les champs');
      return;
    }
    mutation.mutate({ name, price: parseFloat(price) });
  };

  return (
    &lt;View&gt;
      &lt;TextInput
        placeholder="Nom du produit"
        value={name}
        onChangeText={setName}
      /&gt;
      &lt;TextInput
        placeholder="Prix"
        value={price}
        onChangeText={setPrice}
        keyboardType="numeric"
      /&gt;
      &lt;Button
        title={mutation.isPending ? 'Ajout en cours...' : 'Ajouter'}
        onPress={handleSubmit}
        disabled={mutation.isPending}
      /&gt;
    &lt;/View&gt;
  );
}

import { useInfiniteQuery } from '@tanstack/react-query';
import { FlatList, View, Text, ActivityIndicator, Button } from 'react-native';
import axios from 'axios';

const fetchProducts = async ({ pageParam = 1 }) => {
  const response = await axios.get(`https://api.example.com/products?page=${pageParam}&limit=10`);
  return {
    data: response.data.data,
    nextPage: response.data.nextPage,
  };
};

export default function ListeProduitsInfinite() {
  const {
    data,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
    isLoading,
    error,
  } = useInfiniteQuery({
    queryKey: ['products-infinite'],
    queryFn: fetchProducts,
    getNextPageParam: (lastPage) => lastPage.nextPage,
    initialPageParam: 1,
  });

  if (isLoading) {
    return &lt;ActivityIndicator size="large" /&gt;;
  }

  if (error) {
    return &lt;Text&gt;Erreur : {error.message}&lt;/Text&gt;;
  }

  const allProducts = data?.pages.flatMap(page => page.data) || [];

  return (
    &lt;FlatList
      data={allProducts}
      keyExtractor={(item) => item.id.toString()}
      renderItem={({ item }) => &lt;Text&gt;{item.name} - {item.price}€&lt;/Text&gt;}
      onEndReached={() => {
        if (hasNextPage && !isFetchingNextPage) {
          fetchNextPage();
        }
      }}
      onEndReachedThreshold={0.5}
      ListFooterComponent={
        isFetchingNextPage ? &lt;ActivityIndicator size="small" /&gt; : null
      }
    /&gt;
  );
}

import { useQuery } from '@tanstack/react-query';
import { View, Text, ActivityIndicator } from 'react-native';

function UserOrdersScreen() {
  // Première requête : récupérer l'utilisateur
  const {
    data: user,
    isLoading: isLoadingUser,
    error: userError,
  } = useQuery({
    queryKey: ['currentUser'],
    queryFn: fetchCurrentUser,
  });

  // Deuxième requête : dépendante de l'utilisateur
  const {
    data: orders,
    isLoading: isLoadingOrders,
    error: ordersError,
  } = useQuery({
    queryKey: ['orders', user?.id],
    queryFn: () => fetchUserOrders(user.id),
    enabled: !!user, // La requête ne s'exécute que si user existe
  });

  if (isLoadingUser) {
    return &lt;ActivityIndicator size="large" /&gt;;
  }

  if (userError) {
    return &lt;Text&gt;Erreur chargement utilisateur&lt;/Text&gt;;
  }

  if (isLoadingOrders) {
    return &lt;ActivityIndicator size="large" /&gt;;
  }

  return (
    &lt;View&gt;
      &lt;Text&gt;Bienvenue {user.name}&lt;/Text&gt;
      &lt;Text&gt;Nombre de commandes : {orders?.length || 0}&lt;/Text&gt;
    &lt;/View&gt;
  );
}

async function fetchCurrentUser() {
  const response = await axios.get('/api/user');
  return response.data;
}

async function fetchUserOrders(userId) {
  const response = await axios.get(`/api/users/${userId}/orders`);
  return response.data;
}
